## 请求重试机制

### 基础重试
```js
async function fetchWithRetry(url, options = {}, retries = 3) {
  try {
    const res = await fetch(url, options);
    if (!res.ok) throw new Error(`HTTP Error: ${res.status}`);
    return await res.json();
  } catch (error) {
    if (retries > 0) {
      console.log(`请求失败，${retries} 次重试机会`);
      return fetchWithRetry(url, options, retries - 1);
    }
    throw error;
  }
}
```

### 指数退避（Exponential Backoff）
```js
async function fetchWithExponentialBackoff(
  url,
  options = {},
  config = { maxRetries: 3, baseDelay: 1000, maxDelay: 10000 }
) {
  const { maxRetries, baseDelay, maxDelay } = config;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);

      // 4xx 不重试（客户端错误）
      if (res.status >= 400 && res.status < 500) {
        throw new Error(`Client Error: ${res.status}`);
      }

      if (!res.ok) throw new Error(`Server Error: ${res.status}`);

      return await res.json();
    } catch (error) {
      // 最后一次，直接抛出
      if (attempt === maxRetries) throw error;

      // 指数退避 + 随机抖动（避免同时重试造成雪崩）
      const delay = Math.min(
        baseDelay * Math.pow(2, attempt) + Math.random() * 1000,
        maxDelay
      );

      console.log(`第 ${attempt + 1} 次失败，${delay.toFixed(0)}ms 后重试...`);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

// 重试延迟：1s → 2s+抖动 → 4s+抖动（最多 10s）
```

### Axios 拦截器实现重试
```js
import axios from 'axios';

const instance = axios.create({ baseURL: 'https://api.example.com' });

instance.interceptors.response.use(
  response => response,
  async (error) => {
    const { config, response } = error;

    // 设置重试次数
    config._retryCount = config._retryCount || 0;

    // 以下情况不重试：客户端错误、超过次数、取消请求
    if (
      (response?.status >= 400 && response?.status < 500) ||
      config._retryCount >= 3 ||
      axios.isCancel(error)
    ) {
      return Promise.reject(error);
    }

    config._retryCount++;

    const delay = 1000 * Math.pow(2, config._retryCount - 1);
    await new Promise(resolve => setTimeout(resolve, delay));

    return instance(config);
  }
);
```

